"use client";

import { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
import { CaretDownIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { accordionStyles } from "./accordion.styles";

type AccordionRootProps = PropsWithStylex<AccordionPrimitive.Root.Props>;

export function AccordionRoot({
	children,
	style,
	...props
}: AccordionRootProps) {
	return (
		<AccordionPrimitive.Root
			className={(state) => {
				const base = stylex.props(
					accordionStyles.root,
					state.orientation === "vertical" && accordionStyles.rootVertical,
					style,
				);
				return base.className ?? "";
			}}
			{...props}
		>
			{children}
		</AccordionPrimitive.Root>
	);
}

type AccordionItemProps = PropsWithStylex<AccordionPrimitive.Item.Props>;

export function AccordionItem({
	children,
	style,
	...props
}: AccordionItemProps) {
	return (
		<AccordionPrimitive.Item
			className={(state) => {
				const base = stylex.props(
					accordionStyles.item,
					state.disabled && accordionStyles.itemDisabled,
					style,
				);
				return base.className ?? "";
			}}
			{...props}
		>
			{children}
		</AccordionPrimitive.Item>
	);
}

type AccordionHeaderProps = PropsWithStylex<AccordionPrimitive.Header.Props>;

export function AccordionHeader({
	children,
	style,
	...props
}: AccordionHeaderProps) {
	return (
		<AccordionPrimitive.Header
			className={stylex.props(accordionStyles.header, style).className ?? ""}
			{...props}
		>
			{children}
		</AccordionPrimitive.Header>
	);
}

type AccordionTriggerProps = PropsWithStylex<AccordionPrimitive.Trigger.Props>;

export function AccordionTrigger({
	children,
	style,
	...props
}: AccordionTriggerProps) {
	return (
		<AccordionPrimitive.Trigger
			className={(state) => {
				const base = stylex.props(
					accordionStyles.trigger,
					state.open && accordionStyles.triggerOpen,
					style,
				);
				return base.className ?? "";
			}}
			{...props}
		>
			<CaretDownIcon size={16} {...stylex.props(accordionStyles.triggerIcon)} />
			{children}
		</AccordionPrimitive.Trigger>
	);
}

type AccordionPanelProps = PropsWithStylex<AccordionPrimitive.Panel.Props>;

export function AccordionPanel({
	children,
	style,
	...props
}: AccordionPanelProps) {
	return (
		<AccordionPrimitive.Panel
			className={(state) => {
				const base = stylex.props(
					accordionStyles.panel,
					state.open && accordionStyles.panelOpen,
					style,
				);
				return base.className ?? "";
			}}
			{...props}
		>
			{children}
		</AccordionPrimitive.Panel>
	);
}

export const Accordion = {
	Root: AccordionRoot,
	Item: AccordionItem,
	Header: AccordionHeader,
	Trigger: AccordionTrigger,
	Panel: AccordionPanel,
};

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	borderWidth,
	duration,
	easing,
	fontSize,
	fontWeight,
	lineHeight,
	spacing,
} from "@/lib/theme/tokens.stylex";

const dataPanelOpen = "[data-panel-open] &";

export const accordionStyles = stylex.create({
	root: {
		display: "flex",
		flexDirection: "column",
		width: "100%",
		boxSizing: "border-box",
	},
	rootVertical: {
		flexDirection: "column",
	},
	item: {
		borderBottomWidth: borderWidth.thin,
		borderBottomStyle: "solid",
		borderBottomColor: theme.borderSubtle,
	},
	itemDisabled: {
		opacity: 0.5,
	},
	header: {
		margin: 0,
	},
	trigger: {
		display: "flex",
		alignItems: "center",
		gap: spacing.small,
		width: "100%",
		paddingTop: spacing.medium,
		paddingBottom: spacing.medium,
		paddingLeft: spacing.small,
		paddingRight: spacing.small,
		boxSizing: "border-box",
		fontSize: fontSize.small,
		lineHeight: lineHeight.normal,
		fontWeight: fontWeight.medium,
		color: theme.contentPrimary,
		backgroundColor: "transparent",
		border: "none",
		borderRadius: borderRadius.small,
		appearance: "none",
		fontFamily: "inherit",
		textAlign: "left",
		cursor: "pointer",
		WebkitTapHighlightColor: "transparent",
		outline: {
			default: "none",
			":focus-visible": `2px solid ${theme.focusRing}`,
		},
		outlineOffset: "2px",
		":hover": {
			backgroundColor: theme.surfaceHover,
		},
		transitionProperty: "background-color",
		transitionDuration: duration.fast,
		transitionTimingFunction: easing.standard,
	},
	triggerOpen: {},
	triggerIcon: {
		flexShrink: 0,
		color: theme.contentSecondary,
		transform: "rotate(0deg)",
		transitionProperty: "transform",
		transitionDuration: duration.normal,
		transitionTimingFunction: easing.standard,
		[dataPanelOpen]: {
			transform: "rotate(180deg)",
		},
	},
	triggerIconOpen: {},
	panel: {
		overflow: "hidden",
		boxSizing: "border-box",
		transitionProperty: "grid-template-rows, opacity",
		padding: spacing.medium,
		transitionDuration: duration.normal,
		transitionTimingFunction: easing.standard,
	},
	panelOpen: {},
});
